static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmBiasAddHardtanhMishGroupNormCustomTilingData tiling;

    const auto *x_shape = context->GetInputShape(0);
    const auto *w_shape = context->GetInputShape(1);

    // Expect x: [M, K], weight: [N, K]
    const uint32_t rank_x = x_shape->GetStorageShape().GetDimNum();
    const uint32_t rank_w = w_shape->GetStorageShape().GetDimNum();

    if (rank_x < 2 || rank_w < 2) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t M = static_cast<uint32_t>(x_shape->GetStorageShape().GetDim(x_shape->GetStorageShape().GetDimNum() - 2));
    const uint32_t K = static_cast<uint32_t>(x_shape->GetStorageShape().GetDim(x_shape->GetStorageShape().GetDimNum() - 1));
    const uint32_t N = static_cast<uint32_t>(w_shape->GetStorageShape().GetDim(w_shape->GetStorageShape().GetDimNum() - 2));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *numGroups = attrs->GetAttrPointer<int32_t>(0);
    const float *eps = attrs->GetAttrPointer<float>(1);

    // UB budgeting for our manual tiling:
    // For each K-chunk and N-tile we need:
    //   xChunk: tileK
    //   wBlock: tileN * tileK
    //   yTile: tileN
    //   gammaTile + betaTile: 2 * tileN
    //   group buffers (sum, sq, inv): 3 * numGroups
    // Total floats ~= tileK * (tileN + 1) + 3 * tileN + 3 * numGroups
    static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
    static constexpr uint32_t BYTES_PER_FLOAT = 4;
    static constexpr uint32_t ALIGN_TILE_N = 64;
    static constexpr uint32_t ALIGN_TILE_K = 32;

    uint32_t g = (*numGroups > 0) ? static_cast<uint32_t>(*numGroups) : 1u;
    if (g > N) g = N;
    if (N % g != 0) {
        // force to a valid divisor configuration by clamping group number
        for (uint32_t d = g; d >= 1; --d) {
            if (N % d == 0) { g = d; break; }
        }
    }

    // Start with conservative tiles
    uint32_t tileN = (N >= 256u) ? 128u : AlignDown(N, ALIGN_TILE_N);
    if (tileN == 0) tileN = (N < ALIGN_TILE_N) ? N : ALIGN_TILE_N;

    uint32_t tileK = (K >= 512u) ? 64u : AlignDown(K, ALIGN_TILE_K);
    if (tileK == 0) tileK = (K < ALIGN_TILE_K) ? K : ALIGN_TILE_K;

    // Check UB fit and adjust if necessary
    auto FitsUB = [&](uint32_t tN, uint32_t tK) -> bool {
        uint64_t floats = static_cast<uint64_t>(tK) * (static_cast<uint64_t>(tN) + 1ull)
                        + 3ull * static_cast<uint64_t>(tN)
                        + 3ull * static_cast<uint64_t>(g);
        uint64_t bytes = floats * BYTES_PER_FLOAT;
        return bytes <= UB_BUDGET_BYTES;
    };

    while (!FitsUB(tileN, tileK)) {
        if (tileN > ALIGN_TILE_N) {
            tileN = AlignDown(tileN / 2u, ALIGN_TILE_N);
            if (tileN == 0) tileN = ALIGN_TILE_N;
        } else if (tileK > ALIGN_TILE_K) {
            tileK = AlignDown(tileK / 2u, ALIGN_TILE_K);
            if (tileK == 0) tileK = ALIGN_TILE_K;
        } else {
            // last resort
            break;
        }
    }

    // Block dim based on M
    uint32_t blockDim = M;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 32u) blockDim = 32u;
    if (blockDim > M) blockDim = M == 0 ? 1u : M;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);
    tiling.set_numGroups(g);
    tiling.set_eps(*eps);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0; // in-place two-pass on y
    return ge::GRAPH_SUCCESS;
}

